// Générateur de persona avec variables
function createPersona(config) {
  const persona = {
    // Niveau 1 : Identité Core
    base: `Tu es ${config.name}, ${config.title} avec ${config.years} ans d'expérience en ${config.domain}.`,

    // Niveau 2 : Expertise Étendue
    expertise: `
      Spécialités : ${config.specialties.join(', ')}
      Entreprises : ${config.companies.join(' → ')}
      Réalisations : ${config.achievements.join(' | ')}
      Certifications : ${config.certifications.join(', ')}
    `,

    // Niveau 3 : Personnalité Profonde
    personality: `
      Style : ${config.communicationStyle}
      Approche : ${config.methodology}
      Philosophie : "${config.motto}"
      Références : ${config.influences.join(', ')}
      Pet peeves : ${config.dislikes.join(', ')}
    `,

    // Niveau 4 : Contexte Opérationnel
    context: `
      Actuellement : ${config.currentRole} chez ${config.currentCompany}
      Défis : ${config.challenges.join(', ')}
      KPIs : ${config.metrics.join(' | ')}
      Outils : ${config.tools.join(', ')}
    `
  };

  return combinePersonaLevels(persona, config.detailLevel);
}

// Validateur de persona
const personaValidator = {
  checkCoherence: (persona) => {
    const issues = [];

    // Check 1: Expérience vs Âge implicite
    if (persona.includes('30 ans d\'expérience') && 
        persona.includes('millennial')) {
      issues.push('Incohérence temporelle');
    }

    // Check 2: Expertise vs Domaine
    const expertiseMatch = checkExpertiseRelevance(
      persona.expertise,
      persona.taskDomain
    );
    if (expertiseMatch < 0.7) {
      issues.push('Expertise non alignée');
    }

    // Check 3: Niveau vs Responsabilités
    if (persona.level === 'junior' && 
        persona.manages > 10) {
      issues.push('Niveau/responsabilités incohérent');
    }

    // Check 4: Présence de limites
    if (!persona.includes('limitations') && 
        !persona.includes('not an expert in')) {
      issues.push('Persona trop parfait - ajouter des limites');
    }

    return {
      isValid: issues.length === 0,
      issues: issues,
      score: (10 - issues.length) / 10
    };
  }
};

// Sélecteur de format intelligent
const formatSelector = {
  analyze: (taskType, audience, constraints) => {
    const formatMatrix = {
      comparison: {
        executive: 'TABLE',
        technical: 'JSON',
        general: 'PROS_CONS_LIST'
      },
      planning: {
        executive: 'TIMELINE_MILESTONES',
        technical: 'GANTT_ASCII',
        general: 'NUMBERED_STEPS'
      },
      analysis: {
        executive: 'MATRIX_2X2',
        technical: 'DATA_STRUCTURE',
        general: 'BULLET_POINTS'
      },
      documentation: {
        executive: 'EXECUTIVE_SUMMARY',
        technical: 'MARKDOWN_TECHNICAL',
        general: 'STRUCTURED_SECTIONS'
      }
    };

    return {
      recommended: formatMatrix[taskType]?.[audience],
      alternatives: getAlternativeFormats(taskType),
      template: generateTemplate(formatMatrix[taskType]?.[audience])
    };
  }
};

// Template Engine Avancé
class TemplateEngine {
  constructor(template) {
    this.template = template;
    this.variables = this.extractVariables(template);
    this.conditions = this.extractConditions(template);
  }

  // Remplacer les variables
  fill(data) {
    let output = this.template;

    // Remplacer variables simples
    for (let [key, value] of Object.entries(data)) {
      output = output.replace(
        new RegExp(`{{${key}}}`, 'g'), 
        value
      );
    }

    // Appliquer conditions
    output = this.applyConditions(output, data);

    // Retirer sections optionnelles vides
    output = this.cleanOptional(output, data);

    return output;
  }

  // Validation des données
  validate(data) {
    const missing = [];
    const invalid = [];

    this.variables.forEach(v => {
      if (!data[v.name]) missing.push(v.name);
      if (!v.validator(data[v.name])) invalid.push(v.name);
    });

    return {
      isValid: missing.length === 0 && invalid.length === 0,
      missing,
      invalid
    };
  }
}
